// src/components/BackupConfig.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Cloud, ChevronLeft } from 'lucide-react';
import { toast } from 'react-toastify';

export default function BackupConfig() {
  const [cfg, setCfg] = useState(null);
  const [view, setView] = useState('main'); // 'main' | 'dropbox'
  const token = JSON.parse(localStorage.getItem('user') || '{}')?.token;
  const headers = { Authorization: `Bearer ${token}` };

  useEffect(() => {
    axios.get('/api/backup/settings', { headers })
      .then(r => setCfg(r.data))
      .catch(() => setCfg({
        retentionDays: 30,
        destinations: { gdrive:{enabled:false,folderId:''}, dropbox:{enabled:false,folder:'/Backups',accessToken:''} },
        schedule: { enabled:false, days:[1,3,5], times:['03:00'], timezone:'America/Sao_Paulo' }
      }));
  }, []);

  if (!cfg) return <div className="p-6">Carregando…</div>;

  const save = async (next) => {
    try {
      const payload = next || cfg;
      const { data } = await axios.put('/api/backup/settings', payload, { headers });
      setCfg(data);
      toast.success('Configurações salvas!');
    } catch (e) {
      toast.error('Falha ao salvar configurações.');
    }
  };

  const testDropbox = async () => {
    try {
      const { accessToken, folder } = cfg.destinations.dropbox;
      const { data } = await axios.post('/api/backup/test/dropbox', { accessToken, folder }, { headers });
      if (data.ok) toast.success(`Dropbox OK. Pasta: ${data.folder || '(raiz)'}`);
      else toast.error('Não foi possível acessar a pasta/token.');
    } catch (e) {
      toast.error(e.response?.data?.error || 'Falha no teste do Dropbox.');
    }
  };

  const runNowDropbox = async () => {
    try {
      const { data } = await axios.post('/api/backup/run', {
        destinations: ['dropbox'],
        cleanupDays: cfg.retentionDays
      }, { headers });
      toast.success('Backup enviado ao Dropbox!');
      console.log(data);
    } catch (e) {
      toast.error(e.response?.data?.reason || 'Falha ao executar backup.');
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      {view === 'main' && (
        <div className="grid gap-4">
          {/* Card do Dropbox */}
          <button
            onClick={() => setView('dropbox')}
            className="bg-white rounded-2xl shadow p-6 text-left hover:shadow-md transition flex items-center gap-3"
          >
            <Cloud /> <div className="font-semibold">Dropbox</div>
            <div className="ml-auto text-sm text-gray-500">
              {cfg.destinations.dropbox.enabled ? 'Habilitado' : 'Desabilitado'}
            </div>
          </button>
        </div>
      )}

      {view === 'dropbox' && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <button className="flex items-center gap-2 text-blue-600" onClick={() => setView('main')}>
            <ChevronLeft size={18} /> Voltar
          </button>

          <h3 className="text-lg font-semibold">Dropbox</h3>

          <label className="flex items-center gap-2">
            <input
              type="checkbox"
              checked={!!cfg.destinations.dropbox.enabled}
              onChange={(e) => setCfg(prev => ({
                ...prev,
                destinations: {
                  ...prev.destinations,
                  dropbox: { ...prev.destinations.dropbox, enabled: e.target.checked }
                }
              }))}
            />
            Habilitar envio para Dropbox
          </label>

          <div>
            <label className="block text-sm font-medium mb-1">Pasta (ex.: /Backups)</label>
            <input
              type="text"
              className="w-full border rounded px-3 py-2"
              value={cfg.destinations.dropbox.folder || '/Backups'}
              onChange={e => setCfg(prev => ({
                ...prev,
                destinations: {
                  ...prev.destinations,
                  dropbox: { ...prev.destinations.dropbox, folder: e.target.value }
                }
              }))}
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">Access Token (Dropbox)</label>
            <input
              type="password"
              className="w-full border rounded px-3 py-2"
              value={cfg.destinations.dropbox.accessToken || ''}
              onChange={e => setCfg(prev => ({
                ...prev,
                destinations: {
                  ...prev.destinations,
                  dropbox: { ...prev.destinations.dropbox, accessToken: e.target.value }
                }
              }))}
              placeholder="pegar no App Console do Dropbox"
            />
            <p className="text-xs text-gray-500 mt-1">
              Dica: crie um app no Dropbox com escopos <code>files.content.write</code>,
              <code>files.content.read</code> e <code>files.metadata.write</code>.
            </p>
          </div>

          <div className="flex gap-3">
            <button
              onClick={() => save()}
              className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white px-4 py-2 rounded-full"
            >
              Salvar
            </button>
            <button
              onClick={testDropbox}
              className="bg-gray-100 hover:bg-gray-200 px-4 py-2 rounded-full"
            >
              Testar conexão
            </button>
            <button
              onClick={runNowDropbox}
              className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-full ml-auto"
            >
              Executar backup agora
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
